FormScriptItem.Script:
// FormValidation for Contact Us form

//pass in ControlName to validate a single item or nothing to validate everything.
var ErrorReporting = true;

var RunAll = false;
if (ControlName == null) {
  RunAll = true;
}

//Comments - Text Box that must be filled out
if (ControlName == 'CommentsStep2' || RunAll) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue('CommentsStep2'),
      'Blank'
    ) == false
  ) {
    VV.Form.SetValidationErrorMessageOnField(
      'CommentsStep2',
      'A value needs to be entered in the Comments field.'
    );
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField('CommentsStep2');
  }
}

//Email - Email Address is required and must be entered as a valid email address format.
if (ControlName == 'EmailStep0' || RunAll) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue('EmailStep0'),
      'Email'
    ) == false
  ) {
    VV.Form.SetValidationErrorMessageOnField(
      'EmailStep0',
      'Please enter the Email in the form of a valid Email Address.'
    );
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField('EmailStep0');
  }
}

//Frequency - Drop-down must be selected
if (ControlName == 'FrequencyStep1' || RunAll) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue('FrequencyStep1'),
      'DDSelect'
    ) == false
  ) {
    VV.Form.SetValidationErrorMessageOnField(
      'FrequencyStep1',
      'A value needs to be selected in the Frequency field.'
    );
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField('FrequencyStep1');
  }
}

//Name - Textbox that must not be blank or equal to 'Enter your name'.
if (ControlName == 'NameStep0' || RunAll) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue('NameStep0'),
      'Blank'
    ) == false ||
    VV.Form.GetFieldValue('NameStep0') == 'Enter your name'
  ) {
    VV.Form.SetValidationErrorMessageOnField(
      'NameStep0',
      'A value needs to be entered in the Name field.'
    );
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField('NameStep0');
  }
}

//Suggestions - Text Box that must be filled out
if (ControlName == 'SuggestionsStep2' || RunAll) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue('SuggestionsStep2'),
      'Blank'
    ) == false
  ) {
    VV.Form.SetValidationErrorMessageOnField(
      'SuggestionsStep2',
      'A value needs to be entered in the Suggestions field.'
    );
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField('SuggestionsStep2');
  }
}

return ErrorReporting;

if (VV.Form.Template.FormValidation() === true) {
    var messageData = 'The record has been saved.';
    var title = 'Save Form';

    VV.Form.DoAjaxFormSave().then(function (resp) {
        VV.Form.Global.DisplayMessaging(messageData, title);
        VV.Form.SetFieldValue('CompletedSurvey', 'True', true);
    });
} else {
    VV.Form.Global.DisplayMessaging(
        'All of the fields have not been filled in completely or there is an issue with the range of the date entered. Highlight your mouse over the red icon to see how you can resolve the error stopping you from saving this form.', "Error"
    );
}

const emailIsValid = VV.Form.Template.FormValidation('EmailStep0');
const nameIsValid = VV.Form.Template.FormValidation('NameStep0');

console.log({ emailIsValid, nameIsValid })

if (emailIsValid && nameIsValid) {
    VV.Form.SetFieldValue('CurrentStep', '1', true);
}
